def get_user_root(user_id):
    """Get the root directory for a specific user."""
    user_root = os.path.join(UPLOAD_ROOT, secure_filename(str(user_id)))
    os.makedirs(user_root, exist_ok=True)
    return os.path.abspath(user_root)


def resolve_safe_path(user_root, relative_path):
    """
    Safely resolve a user-provided relative path within the user's root directory.
    Prevents path traversal attacks by ensuring the resolved path stays within user_root.
    """
    if relative_path is None:
        relative_path = ''

    # Normalize the path to handle '..' and other path components
    normalized = os.path.normpath(relative_path)

    # Join with user root
    full_path = os.path.join(user_root, normalized)

    # Get the absolute path
    full_path = os.path.abspath(full_path)

    # Security check: ensure the resolved path is within the user's root directory
    if not full_path.startswith(os.path.abspath(user_root)):
        return None

    return full_path


def get_file_info(file_path, user_root):
    """Get detailed information about a file or directory."""
    stat = os.stat(file_path)
    relative_path = os.path.relpath(file_path, user_root)
    if relative_path == '.':
        relative_path = ''

    info = {
        'name': os.path.basename(file_path) or '/',
        'path': relative_path,
        'is_directory': os.path.isdir(file_path),
        'size': stat.st_size if os.path.isfile(file_path) else None,
        'size_human': format_size(stat.st_size) if os.path.isfile(file_path) else None,
        'created': datetime.fromtimestamp(stat.st_ctime).isoformat(),
        'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
        'accessed': datetime.fromtimestamp(stat.st_atime).isoformat(),
    }

    if os.path.isfile(file_path):
        _, ext = os.path.splitext(file_path)
        info['extension'] = ext.lstrip('.').lower() if ext else None
        info['mime_type'] = get_mime_type(file_path)

    if os.path.isdir(file_path):
        try:
            contents = os.listdir(file_path)
            info['num_items'] = len(contents)
            info['num_files'] = sum(1 for c in contents if os.path.isfile(os.path.join(file_path, c)))
            info['num_directories'] = sum(1 for c in contents if os.path.isdir(os.path.join(file_path, c)))
        except PermissionError:
            info['num_items'] = None

    return info


def format_size(size_bytes):
    """Format file size in human-readable format."""
    if size_bytes == 0:
        return '0 B'
    units = ['B', 'KB', 'MB', 'GB', 'TB']
    i = 0
    size = float(size_bytes)
    while size >= 1024 and i < len(units) - 1:
        size /= 1024
        i += 1
    return f'{size:.2f} {units[i]}'


def get_mime_type(file_path):
    """Get MIME type for a file."""
    import mimetypes
    mime_type, _ = mimetypes.guess_type(file_path)
    return mime_type or 'application/octet-stream'


def allowed_file(filename):
    """Check if a file extension is allowed."""
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def get_user_id_from_request():
    """Extract user_id from request. In production, this would come from authentication."""
    user_id = request.headers.get('X-User-ID') or request.args.get('user_id')
    if not user_id:
        return None
    return secure_filename(str(user_id))


