@app.route('/api/files/list', methods=['GET'])
def list_directory():
    """List contents of a directory."""
    user_id = get_user_id_from_request()
    user_root = get_user_root(user_id)
    relative_path = request.args.get('path', '')

    full_path = resolve_safe_path(user_root, relative_path)
    if full_path is None:
        return jsonify({'error': 'Invalid path: path traversal detected.'}), 403

    if not os.path.exists(full_path):
        return jsonify({'error': f'Path does not exist: {relative_path}'}), 404

    if not os.path.isdir(full_path):
        return jsonify({'error': f'Path is not a directory: {relative_path}'}), 400

    try:
        entries = []
        for entry_name in sorted(os.listdir(full_path)):
            entry_path = os.path.join(full_path, entry_name)
            entry_relative = os.path.relpath(entry_path, user_root)
            stat = os.stat(entry_path)

            entry_info = {
                'name': entry_name,
                'path': entry_relative,
                'is_directory': os.path.isdir(entry_path),
                'size': stat.st_size if os.path.isfile(entry_path) else None,
                'size_human': format_size(stat.st_size) if os.path.isfile(entry_path) else None,
                'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
            }

            if os.path.isfile(entry_path):
                _, ext = os.path.splitext(entry_name)
                entry_info['extension'] = ext.lstrip('.').lower() if ext else None

            entries.append(entry_info)

        current_relative = os.path.relpath(full_path, user_root)
        if current_relative == '.':
            current_relative = ''

        # Compute parent path
        parent_path = None
        if current_relative:
            parent = os.path.dirname(current_relative)
            parent_path = parent if parent != current_relative else ''

        return jsonify({
            'path': current_relative,
            'parent_path': parent_path,
            'total_items': len(entries),
            'directories': sum(1 for e in entries if e['is_directory']),
            'files': sum(1 for e in entries if not e['is_directory']),
            'entries': entries
        })

    except PermissionError:
        return jsonify({'error': 'Permission denied.'}), 403


@app.route('/api/files/download', methods=['GET'])
def download_file():
    """Download a file."""
    user_id = get_user_id_from_request()
    user_root = get_user_root(user_id)
    relative_path = request.args.get('path', '')

    if not relative_path:
        return jsonify({'error': 'Path parameter is required.'}), 400

    full_path = resolve_safe_path(user_root, relative_path)
    if full_path is None:
        return jsonify({'error': 'Invalid path: path traversal detected.'}), 403

    if not os.path.exists(full_path):
        return jsonify({'error': f'File not found: {relative_path}'}), 404

    if not os.path.isfile(full_path):
        return jsonify({'error': f'Path is not a file: {relative_path}'}), 400

    try:
        return send_file(
            full_path,
            as_attachment=True,
            download_name=os.path.basename(full_path)
        )
    except Exception as e:
        return jsonify({'error': f'Failed to download file: {str(e)}'}), 500


