@app.route('/api/files/upload', methods=['POST'])
def upload_file():
    """Upload a file to the specified directory."""
    user_id = get_user_id_from_request()
    user_root = get_user_root(user_id)
    relative_path = request.form.get('path', '')

    if 'file' not in request.files:
        return jsonify({'error': 'No file provided in request.'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No file selected.'}), 400

    if not allowed_file(file.filename):
        return jsonify({
            'error': f'File type not allowed. Allowed types: {", ".join(sorted(ALLOWED_EXTENSIONS))}'
        }), 400

    # Resolve the target directory
    target_dir = resolve_safe_path(user_root, relative_path)
    if target_dir is None:
        return jsonify({'error': 'Invalid path: path traversal detected.'}), 403

    # Create directory if it doesn't exist
    os.makedirs(target_dir, exist_ok=True)

    if not os.path.isdir(target_dir):
        return jsonify({'error': f'Target path is not a directory: {relative_path}'}), 400

    filename = secure_filename(file.filename)
    file_path = os.path.join(target_dir, filename)

    # Handle duplicate filenames
    if os.path.exists(file_path):
        name, ext = os.path.splitext(filename)
        counter = 1
        while os.path.exists(file_path):
            filename = f'{name}_{counter}{ext}'
            file_path = os.path.join(target_dir, filename)
            counter += 1

    try:
        file.save(file_path)
        info = get_file_info(file_path, user_root)
        return jsonify({
            'message': 'File uploaded successfully.',
            'file': info
        }), 201
    except Exception as e:
        return jsonify({'error': f'Failed to upload file: {str(e)}'}), 500


@app.route('/api/files/mkdir', methods=['POST'])
def create_directory():
    """Create a new directory."""
    user_id = get_user_id_from_request()
    user_root = get_user_root(user_id)

    data = request.get_json()
    if not data or 'path' not in data:
        return jsonify({'error': 'Path is required in JSON body.'}), 400

    relative_path = data['path']
    full_path = resolve_safe_path(user_root, relative_path)
    if full_path is None:
        return jsonify({'error': 'Invalid path: path traversal detected.'}), 403

    if os.path.exists(full_path):
        return jsonify({'error': f'Path already exists: {relative_path}'}), 409

    try:
        os.makedirs(full_path, exist_ok=False)
        info = get_file_info(full_path, user_root)
        return jsonify({
            'message': 'Directory created successfully.',
            'directory': info
        }), 201
    except FileExistsError:
        return jsonify({'error': f'Directory already exists: {relative_path}'}), 409
    except Exception as e:
        return jsonify({'error': f'Failed to create directory: {str(e)}'}), 500


@app.route('/api/files/delete', methods=['DELETE'])
def delete_file():
    """Delete a file or directory."""
    user_id = get_user_id_from_request()
    user_root = get_user_root(user_id)
    relative_path = request.args.get('path', '')

    if not relative_path:
        return jsonify({'error': 'Cannot delete root directory.'}), 400

    full_path = resolve_safe_path(user_root, relative_path)
    if full_path is None:
        return jsonify({'error': 'Invalid path: path traversal detected.'}), 403

    # Prevent deleting the user root
    if os.path.abspath(full_path) == os.path.abspath(user_root):
        return jsonify({'error': 'Cannot delete root directory.'}), 400

    if not os.path.exists(full_path):
        return jsonify({'error': f'Path does not exist: {relative_path}'}), 404

    try:
        if os.path.isfile(full_path):
            os.remove(full_path)
            return jsonify({'message': f'File deleted: {relative_path}'})
        elif os.path.isdir(full_path):
            recursive = request.args.get('recursive', 'false').lower() == 'true'
            if recursive:
                shutil.rmtree(full_path)
            else:
                try:
                    os.rmdir(full_path)
                except OSError:
                    return jsonify({
                        'error': 'Directory is not empty. Use recursive=true to delete non-empty directories.'
                    }), 400
            return jsonify({'message': f'Directory deleted: {relative_path}'})
    except PermissionError:
        return jsonify({'error': 'Permission denied.'}), 403
    except Exception as e:
        return jsonify({'error': f'Failed to delete: {str(e)}'}), 500


@app.route('/api/files/move', methods=['POST'])
def move_file():
    """Move or rename a file or directory."""
    user_id = get_user_id_from_request()
    user_root = get_user_root(user_id)

    data = request.get_json()
    if not data or 'source' not in data or 'destination' not in data:
        return jsonify({'error': 'Both source and destination are required in JSON body.'}), 400

    source_path = resolve_safe_path(user_root, data['source'])
    dest_path = resolve_safe_path(user_root, data['destination'])

    if source_path is None or dest_path is None:
        return jsonify({'error': 'Invalid path: path traversal detected.'}), 403

    if not os.path.exists(source_path):
        return jsonify({'error': f'Source does not exist: {data["source"]}'}), 404

    if os.path.exists(dest_path):
        return jsonify({'error': f'Destination already exists: {data["destination"]}'}), 409

    # Ensure parent directory of destination exists
    dest_parent = os.path.dirname(dest_path)
    if not os.path.exists(dest_parent):
        os.makedirs(dest_parent, exist_ok=True)

    try:
        shutil.move(source_path, dest_path)
        info = get_file_info(dest_path, user_root)
        return jsonify({
            'message': 'Moved successfully.',
            'source': data['source'],
            'destination': data['destination'],
            'item': info
        })
    except Exception as e:
        return jsonify({'error': f'Failed to move: {str(e)}'}), 500


@app.route('/api/files/search', methods=['GET'])
def search_files():
    """Search for files by name."""
    user_id = get_user_id_from_request()
    user_root = get_user_root(user_id)
    query = request.args.get('query', '')
    search_path = request.args.get('path', '')

    if not query:
        return jsonify({'error': 'Query parameter is required.'}), 400

    search_root = resolve_safe_path(user_root, search_path)
    if search_root is None:
        return jsonify({'error': 'Invalid path: path traversal detected.'}), 403

    if not os.path.exists(search_root):
        return jsonify({'error': f'Search path does not exist: {search_path}'}), 404

    if not os.path.isdir(search_root):
        return jsonify({'error': f'Search path is not a directory: {search_path}'}), 400

    results = []
    max_results = int(request.args.get('limit', 100))
    query_lower = query.lower()

    try:
        for dirpath, dirnames, filenames in os.walk(search_root):
            for name in filenames + dirnames:
                if query_lower in name.lower():
                    entry_path = os.path.join(dirpath, name)
                    entry_relative = os.path.relpath(entry_path, user_root)
                    stat = os.stat(entry_path)

                    results.append({
                        'name': name,
                        'path': entry_relative,
                        'is_directory': os.path.isdir(entry_path),
                        'size': stat.st_size if os.path.isfile(entry_path) else None,
                        'size_human': format_size(stat.st_size) if os.path.isfile(entry_path) else None,
                        'modified': datetime.fromtimestamp(stat.st_mtime).isoformat(),
                    })

                    if len(results) >= max_results:
                        break
            if len(results) >= max_results:
                break

        return jsonify({
            'query': query,
            'search_path': search_path or '/',
            'total_results': len(results),
            'results': results
        })

    except PermissionError:
        return jsonify({'error': 'Permission denied.'}), 403
    except Exception as e:
        return jsonify({'error': f'Search failed: {str(e)}'}), 500


